import sqlite3, os, json

DB_PATH = os.path.join(os.path.dirname(__file__), "aeo_data.db")

def init_db():
    """Create aeo_data.db from embedded data if it doesn't exist or is empty."""
    needs_full_init = True
    needs_respuestas = True

    if os.path.exists(DB_PATH) and os.path.getsize(DB_PATH) > 0:
        try:
            conn = sqlite3.connect(DB_PATH)
            count = conn.execute("SELECT COUNT(*) FROM metricas").fetchone()[0]
            if count > 0:
                needs_full_init = False
            # Check if respuestas table exists and has data
            try:
                rc = conn.execute("SELECT COUNT(*) FROM respuestas").fetchone()[0]
                if rc > 0:
                    needs_respuestas = False
            except Exception:
                pass  # table doesn't exist yet
            conn.close()
            if not needs_full_init and not needs_respuestas:
                return  # DB fully up to date
        except Exception:
            pass  # DB is corrupt, recreate

    conn = sqlite3.connect(DB_PATH)
    c = conn.cursor()

    c.execute("""CREATE TABLE IF NOT EXISTS metricas (
        batch_id TEXT, batch_date TEXT, batch_month TEXT, batch_quarter TEXT,
        prompt_id TEXT, country_id TEXT, product_category TEXT, funnel_stage TEXT,
        source_producto_raw TEXT, prompt_text TEXT, model_source TEXT,
        num_replicates INTEGER, num_success INTEGER, mention_rate REAL,
        citation_rate REAL, consistency_score REAL, avg_brand_mentions REAL,
        avg_response_length REAL, avg_rank_alegra REAL, avg_pos_pct_alegra REAL,
        ranks_alegra TEXT, eco_cites INTEGER, ext_cites INTEGER, total_cites INTEGER,
        eco_share_pct REAL, top_brand TEXT, top_brand_rank REAL
    )""")

    c.execute("""CREATE TABLE IF NOT EXISTS marcas (
        batch_id TEXT, batch_date TEXT, prompt_id TEXT, country_id TEXT,
        model_source TEXT, funnel_stage TEXT, product_category TEXT,
        brand_name TEXT, brand_rank_avg REAL, brand_presence_pct REAL,
        brand_mentions_total INTEGER, brand_ranks_by_rep TEXT,
        is_top_brand INTEGER, is_alegra INTEGER
    )""")

    c.execute("""CREATE TABLE IF NOT EXISTS dominios (
        batch_id TEXT, batch_date TEXT, prompt_id TEXT, country_id TEXT,
        model_source TEXT, domain TEXT, cite_count INTEGER,
        is_ecosystem INTEGER, ecosystem_brand TEXT
    )""")

    c.execute("""CREATE TABLE IF NOT EXISTS respuestas (
        batch_id TEXT, prompt_id TEXT, model_source TEXT,
        replicate_id INTEGER, raw_response_text TEXT, raw_citations_json TEXT
    )""")

