    if needs_full_init:
        for table_name, rows in DATA.items():
            if not rows:
                continue
            cols = list(rows[0].keys())
            placeholders = ",".join(["?"] * len(cols))
            col_names = ",".join(cols)
            c.execute(f"DELETE FROM {table_name}")
            for row in rows:
                vals = [row.get(col) for col in cols]
                c.execute(f"INSERT INTO {table_name} ({col_names}) VALUES ({placeholders})", vals)

    # Load respuestas from JSON file
    if needs_respuestas:
        resp_path = os.path.join(os.path.dirname(__file__), "respuestas_data.json")
        if os.path.exists(resp_path):
            with open(resp_path, "r", encoding="utf-8") as f:
                resp_data = json.load(f)
            c.execute("DELETE FROM respuestas")
            for r in resp_data:
                c.execute("INSERT INTO respuestas VALUES (?,?,?,?,?,?)", (
                    r["batch_id"], r["prompt_id"], r["model_source"],
                    r["replicate_id"], r["raw_response_text"], r["raw_citations_json"],
                ))
            print(f"Loaded {len(resp_data)} respuestas")

    conn.commit()
    conn.close()
    print(f"Database initialized: {DB_PATH}")

